from __future__ import annotations

import json
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Dict, List, Optional

BASE = Path(r"C:\Users\User-OEM\.openclaw\workspace\task_watchdog")
CONFIG_PATH = BASE / "config.json"
ACTIVE_PATH = BASE / "active_tasks.json"
HISTORY_PATH = BASE / "task_history.jsonl"


def now_iso() -> str:
    return datetime.now(timezone.utc).astimezone().isoformat()


def load_json(path: Path, default: Any):
    if not path.exists():
        return default
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return default


def save_json_atomic(path: Path, data: Any) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp = path.with_suffix(path.suffix + ".tmp")
    tmp.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    tmp.replace(path)


def append_history(entry: Dict[str, Any]) -> None:
    HISTORY_PATH.parent.mkdir(parents=True, exist_ok=True)
    with HISTORY_PATH.open("a", encoding="utf-8") as f:
        f.write(json.dumps(entry, ensure_ascii=False) + "\n")


def format_human_dt(iso_str: Optional[str]) -> Optional[str]:
    if not iso_str:
        return None
    try:
        dt = datetime.fromisoformat(iso_str)
        return dt.strftime("%d/%m %H:%M")
    except Exception:
        return iso_str


def minutes_since(iso_str: Optional[str]) -> Optional[int]:
    if not iso_str:
        return None
    try:
        dt = datetime.fromisoformat(iso_str)
        delta = datetime.now(dt.tzinfo or timezone.utc) - dt
        return max(0, int(delta.total_seconds() // 60))
    except Exception:
        return None


def build_running_message(task: Dict[str, Any]) -> str:
    started = format_human_dt(task.get("startedAt"))
    elapsed = minutes_since(task.get("startedAt"))
    checked = format_human_dt(task.get("lastCheckedAt"))
    step = task.get("lastKnownStep") or "sem passo detalhado"
    model = task.get("model") or "modelo não registado"
    who = task.get("launcher") or "Tobias"
    return (
        f"Tarefa em andamento: {task.get('taskName', 'sem nome')}\n"
        f"Tipo: {task.get('type', 'desconhecido')}\n"
        f"Modelo: {model}\n"
        f"Lançada por: {who}\n"
        f"Iniciada: {started or 'desconhecido'}\n"
        f"Rodando há: {str(elapsed) + ' min' if elapsed is not None else 'desconhecido'}\n"
        f"Último passo conhecido: {step}\n"
        f"Última checagem: {checked or 'desconhecido'}"
    )


def build_finished_message(task: Dict[str, Any]) -> str:
    started = format_human_dt(task.get("startedAt"))
    ended = format_human_dt(task.get("endedAt"))
    elapsed = minutes_since(task.get("startedAt"))
    model = task.get("model") or "modelo não registado"
    result = task.get("resultSummary") or "sem resumo adicional"
    return (
        f"Tarefa finalizada: {task.get('taskName', 'sem nome')}\n"
        f"Modelo: {model}\n"
        f"Iniciada: {started or 'desconhecido'}\n"
        f"Encerrada: {ended or 'desconhecido'}\n"
        f"Duração observada: {str(elapsed) + ' min' if elapsed is not None else 'desconhecida'}\n"
        f"Resumo: {result}"
    )


def build_failed_message(task: Dict[str, Any]) -> str:
    started = format_human_dt(task.get("startedAt"))
    failed = format_human_dt(task.get("endedAt"))
    elapsed = minutes_since(task.get("startedAt"))
    model = task.get("model") or "modelo não registado"
    err = task.get("error") or "sem erro detalhado"
    step = task.get("lastKnownStep") or "passo desconhecido"
    return (
        f"Tarefa falhou: {task.get('taskName', 'sem nome')}\n"
        f"Modelo: {model}\n"
        f"Iniciada: {started or 'desconhecido'}\n"
        f"Falha detectada: {failed or 'desconhecido'}\n"
        f"Rodou por: {str(elapsed) + ' min' if elapsed is not None else 'desconhecido'}\n"
        f"Último passo conhecido: {step}\n"
        f"Erro: {err}"
    )


def evaluate_tasks(tasks: List[Dict[str, Any]], config: Dict[str, Any]) -> Dict[str, Any]:
    now = now_iso()
    notify_every = int(config.get("notifyEveryMinutes", 10))
    outputs: List[Dict[str, Any]] = []
    remaining: List[Dict[str, Any]] = []

    for task in tasks:
        task["lastCheckedAt"] = now
        status = task.get("status", "running")
        last_notified = task.get("lastNotifiedAt")
        mins = minutes_since(last_notified)

        if status == "running":
            if last_notified is None or (mins is not None and mins >= notify_every):
                outputs.append({
                    "taskId": task.get("taskId"),
                    "kind": "running",
                    "message": build_running_message(task),
                    "originChat": task.get("originChat"),
                })
                task["lastNotifiedAt"] = now
            remaining.append(task)
            continue

        if status == "completed":
            task.setdefault("endedAt", now)
            outputs.append({
                "taskId": task.get("taskId"),
                "kind": "completed",
                "message": build_finished_message(task),
                "originChat": task.get("originChat"),
            })
            append_history(task)
            continue

        if status == "failed":
            task.setdefault("endedAt", now)
            outputs.append({
                "taskId": task.get("taskId"),
                "kind": "failed",
                "message": build_failed_message(task),
                "originChat": task.get("originChat"),
            })
            append_history(task)
            continue

        remaining.append(task)

    return {"checkedAt": now, "notifications": outputs, "remaining": remaining}


def main() -> None:
    config = load_json(CONFIG_PATH, {})
    if not config.get("enabled", True):
        print(json.dumps({"enabled": False}, ensure_ascii=False))
        return
    tasks = load_json(ACTIVE_PATH, [])
    result = evaluate_tasks(tasks, config)
    save_json_atomic(ACTIVE_PATH, result["remaining"])
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

from __future__ import annotations

import json
from datetime import datetime, timedelta, timezone
from pathlib import Path
from typing import Any, Dict, List, Set

BASE = Path(r"C:\Users\User-OEM\.openclaw\workspace\task_watchdog")
ACTIVE_PATH = BASE / "active_tasks.json"
SCAN_MINUTES = 20


def now_local() -> datetime:
    return datetime.now(timezone.utc).astimezone()


def iso_now() -> str:
    return now_local().isoformat()


def load_active() -> List[Dict[str, Any]]:
    if not ACTIVE_PATH.exists():
        return []
    try:
        return json.loads(ACTIVE_PATH.read_text(encoding="utf-8"))
    except Exception:
        return []


def save_active(tasks: List[Dict[str, Any]]) -> None:
    ACTIVE_PATH.parent.mkdir(parents=True, exist_ok=True)
    tmp = ACTIVE_PATH.with_suffix('.json.tmp')
    tmp.write_text(json.dumps(tasks, ensure_ascii=False, indent=2), encoding='utf-8')
    tmp.replace(ACTIVE_PATH)


def format_human(dt: datetime) -> str:
    return dt.strftime('%d/%m %H:%M')


def scan_subagent_sessions() -> List[Dict[str, Any]]:
    sessions_path = Path(r"C:\Users\User-OEM\.openclaw\sessions.json")
    if not sessions_path.exists():
        return []
    try:
        data = json.loads(sessions_path.read_text(encoding='utf-8'))
    except Exception:
        return []

    now = now_local()
    cutoff = now - timedelta(minutes=SCAN_MINUTES)
    found = []

    if isinstance(data, list):
        items = data
    elif isinstance(data, dict):
        items = data.get('sessions', []) or data.get('items', []) or []
    else:
        items = []

    for item in items:
        key = item.get('key') or item.get('sessionKey') or ''
        if 'subagent' not in key:
            continue
        updated_raw = item.get('updatedAt') or item.get('lastMessageAt') or item.get('createdAt')
        if not updated_raw:
            continue
        try:
            updated = datetime.fromisoformat(updated_raw.replace('Z', '+00:00')).astimezone()
        except Exception:
            continue
        if updated < cutoff:
            continue
        found.append({
            'sessionKey': key,
            'updatedAt': updated.isoformat(),
            'label': item.get('label') or item.get('name') or 'subagent sem label'
        })
    return found


def main() -> None:
    active = load_active()
    tracked_keys: Set[str] = {t.get('childSessionKey') for t in active if t.get('childSessionKey')}
    scanned = scan_subagent_sessions()
    added = []
    now = iso_now()

    for sess in scanned:
        key = sess['sessionKey']
        if key in tracked_keys:
            continue
        task = {
            'taskId': f"auto_{abs(hash(key))}",
            'taskName': sess.get('label') or 'Subagente detectado automaticamente',
            'type': 'subagent',
            'model': 'desconhecido (auto-detected)',
            'originChat': 'telegram:1962323981',
            'originSession': 'auto-detected',
            'replyTarget': 'current_chat',
            'startedAt': sess.get('updatedAt') or now,
            'lastCheckedAt': now,
            'lastNotifiedAt': None,
            'notifyEveryMinutes': 10,
            'status': 'running',
            'childSessionKey': key,
            'summaryHint': 'detectado automaticamente pelo auditor de launches',
            'lastKnownStep': 'detected_unregistered_launch',
            'launcher': 'Tobias (auto-audit)'
        }
        active.append(task)
        added.append(task)

    save_active(active)
    print(json.dumps({
        'checkedAt': now,
        'detected': len(scanned),
        'added': len(added),
        'items': added,
    }, ensure_ascii=False, indent=2))


if __name__ == '__main__':
    main()

